import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;

public class PreparedStatementCRUD {
    private static final String URL = "jdbc:mysql://localhost:3306/company";
    private static final String USER = "root";
    private static final String PASS = "password";

    public static void main(String[] args) {
        try (Connection conn = DriverManager.getConnection(URL, USER, PASS)) {
            // CREATE
            insertEmployee(conn, "John Doe", "Engineering", 75000.00);
            insertEmployee(conn, "Jane Smith", "Marketing", 68000.00);
            System.out.println("Employees inserted successfully.");

            // READ
            System.out.println("\nAll Employees:");
            listEmployees(conn);

            // UPDATE
            updateSalary(conn, "John Doe", 82000.00);
            System.out.println("\nAfter salary update:");
            listEmployees(conn);

            // DELETE
            deleteEmployee(conn, "Jane Smith");
            System.out.println("\nAfter deletion:");
            listEmployees(conn);

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    static void insertEmployee(Connection conn, String name, String dept, double salary)
            throws SQLException {
        String sql = "INSERT INTO employees (name, department, salary) VALUES (?, ?, ?)";
        try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
            pstmt.setString(1, name);
            pstmt.setString(2, dept);
            pstmt.setDouble(3, salary);
            pstmt.executeUpdate();
        }
    }

    static void listEmployees(Connection conn) throws SQLException {
        String sql = "SELECT name, department, salary FROM employees";
        try (PreparedStatement pstmt = conn.prepareStatement(sql);
             ResultSet rs = pstmt.executeQuery()) {
            while (rs.next()) {
                System.out.printf("  %s | %s | $%.2f%n",
                    rs.getString("name"),
                    rs.getString("department"),
                    rs.getDouble("salary"));
            }
        }
    }

    static void updateSalary(Connection conn, String name, double newSalary)
            throws SQLException {
        String sql = "UPDATE employees SET salary = ? WHERE name = ?";
        try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
            pstmt.setDouble(1, newSalary);
            pstmt.setString(2, name);
            int rowsUpdated = pstmt.executeUpdate();
            System.out.println("Rows updated: " + rowsUpdated);
        }
    }

    static void deleteEmployee(Connection conn, String name) throws SQLException {
        String sql = "DELETE FROM employees WHERE name = ?";
        try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
            pstmt.setString(1, name);
            int rowsDeleted = pstmt.executeUpdate();
            System.out.println("Rows deleted: " + rowsDeleted);
        }
    }
}

import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.Savepoint;
import java.sql.SQLException;
import java.sql.Statement;

public class TransactionBatchExample {
    public static void main(String[] args) {
        String url = "jdbc:mysql://localhost:3306/bank";

        try (Connection conn = DriverManager.getConnection(url, "root", "password")) {
            conn.setAutoCommit(false);
            conn.setTransactionIsolation(Connection.TRANSACTION_READ_COMMITTED);

            try {
                // Phase 1: Fund transfer
                String debitSql = "UPDATE accounts SET balance = balance - ? WHERE account_id = ?";
                String creditSql = "UPDATE accounts SET balance = balance + ? WHERE account_id = ?";

                try (PreparedStatement debitStmt = conn.prepareStatement(debitSql);
                     PreparedStatement creditStmt = conn.prepareStatement(creditSql)) {

                    debitStmt.setDouble(1, 5000.00);
                    debitStmt.setInt(2, 1001);
                    debitStmt.executeUpdate();

                    creditStmt.setDouble(1, 5000.00);
                    creditStmt.setInt(2, 1002);
                    creditStmt.executeUpdate();
                }
                System.out.println("Phase 1: Fund transfer completed.");

                // Create savepoint after successful transfer
                Savepoint transferComplete = conn.setSavepoint("TRANSFER_DONE");

                // Phase 2: Batch insert transaction logs
                String logSql = "INSERT INTO transaction_log (account_id, type, amount, description) VALUES (?, ?, ?, ?)";
                try (PreparedStatement logStmt = conn.prepareStatement(logSql)) {
                    logStmt.setInt(1, 1001);
                    logStmt.setString(2, "DEBIT");
                    logStmt.setDouble(3, 5000.00);
                    logStmt.setString(4, "Transfer to account 1002");
                    logStmt.addBatch();

                    logStmt.setInt(1, 1002);
                    logStmt.setString(2, "CREDIT");
                    logStmt.setDouble(3, 5000.00);
                    logStmt.setString(4, "Transfer from account 1001");
                    logStmt.addBatch();

                    int[] batchResults = logStmt.executeBatch();
                    System.out.println("Phase 2: " + batchResults.length + " log entries inserted.");
                } catch (SQLException batchEx) {
                    System.err.println("Batch logging failed, rolling back to savepoint.");
                    conn.rollback(transferComplete);
                }

                conn.commit();
                System.out.println("Transaction committed successfully.");

            } catch (SQLException ex) {
                conn.rollback();
                System.err.println("Transaction rolled back: " + ex.getMessage());
            }
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

import java.sql.*;
import java.util.ArrayList;
import java.util.List;

// Generic DAO interface
interface GenericDAO<T> {
    T findById(int id) throws SQLException;
    List<T> findAll() throws SQLException;
    int save(T entity) throws SQLException;
    int update(T entity) throws SQLException;
    int delete(int id) throws SQLException;
}

// Product entity
class Product {
    private int id;
    private String name;
    private String category;
    private double price;
    private int quantity;

    public Product() {}

    public Product(String name, String category, double price, int quantity) {
        this.name = name;
        this.category = category;
        this.price = price;
        this.quantity = quantity;
    }

    // Getters and setters
    public int getId() { return id; }
    public void setId(int id) { this.id = id; }
    public String getName() { return name; }
    public void setName(String name) { this.name = name; }
    public String getCategory() { return category; }
    public void setCategory(String category) { this.category = category; }
    public double getPrice() { return price; }
    public void setPrice(double price) { this.price = price; }
    public int getQuantity() { return quantity; }
    public void setQuantity(int quantity) { this.quantity = quantity; }

    @Override
    public String toString() {
        return String.format("Product[id=%d, name=%s, category=%s, price=%.2f, qty=%d]",
            id, name, category, price, quantity);
    }
}

// Product DAO implementation
class ProductDAO implements GenericDAO<Product> {
    private final Connection connection;

    public ProductDAO(Connection connection) {
        this.connection = connection;
    }

    @Override
    public Product findById(int id) throws SQLException {
        String sql = "SELECT * FROM products WHERE id = ?";
        try (PreparedStatement pstmt = connection.prepareStatement(sql)) {
            pstmt.setInt(1, id);
            try (ResultSet rs = pstmt.executeQuery()) {
                if (rs.next()) {
                    return mapRow(rs);
                }
            }
        }
        return null;
    }

    @Override
    public List<Product> findAll() throws SQLException {
        List<Product> products = new ArrayList<>();
        String sql = "SELECT * FROM products ORDER BY id";
        try (Statement stmt = connection.createStatement();
             ResultSet rs = stmt.executeQuery(sql)) {
            while (rs.next()) {
                products.add(mapRow(rs));
            }
        }
        return products;
    }

    @Override
    public int save(Product product) throws SQLException {
        String sql = "INSERT INTO products (name, category, price, quantity) VALUES (?, ?, ?, ?)";
        try (PreparedStatement pstmt = connection.prepareStatement(sql, Statement.RETURN_GENERATED_KEYS)) {
            pstmt.setString(1, product.getName());
            pstmt.setString(2, product.getCategory());
            pstmt.setDouble(3, product.getPrice());
            pstmt.setInt(4, product.getQuantity());
            int rows = pstmt.executeUpdate();

            try (ResultSet keys = pstmt.getGeneratedKeys()) {
                if (keys.next()) {
                    product.setId(keys.getInt(1));
                }
            }
            return rows;
        }
    }

    @Override
    public int update(Product product) throws SQLException {
        String sql = "UPDATE products SET name=?, category=?, price=?, quantity=? WHERE id=?";
        try (PreparedStatement pstmt = connection.prepareStatement(sql)) {
            pstmt.setString(1, product.getName());
            pstmt.setString(2, product.getCategory());
            pstmt.setDouble(3, product.getPrice());
            pstmt.setInt(4, product.getQuantity());
            pstmt.setInt(5, product.getId());
            return pstmt.executeUpdate();
        }
    }

    @Override
    public int delete(int id) throws SQLException {
        String sql = "DELETE FROM products WHERE id = ?";
        try (PreparedStatement pstmt = connection.prepareStatement(sql)) {
            pstmt.setInt(1, id);
            return pstmt.executeUpdate();
        }
    }

    private Product mapRow(ResultSet rs) throws SQLException {
        Product p = new Product();
        p.setId(rs.getInt("id"));
        p.setName(rs.getString("name"));
        p.setCategory(rs.getString("category"));
        p.setPrice(rs.getDouble("price"));
        p.setQuantity(rs.getInt("quantity"));
        return p;
    }
}

// Main application
public class ProductApp {
    public static void main(String[] args) {
        String url = "jdbc:mysql://localhost:3306/store";

        try (Connection conn = DriverManager.getConnection(url, "root", "password")) {
            ProductDAO dao = new ProductDAO(conn);

            // Save products
            dao.save(new Product("Laptop", "Electronics", 999.99, 50));
            dao.save(new Product("Headphones", "Electronics", 149.99, 200));
            dao.save(new Product("Coffee Maker", "Appliances", 79.99, 100));

            // List all products
            System.out.println("All Products:");
            for (Product p : dao.findAll()) {
                System.out.println("  " + p);
            }

            // Find by ID
            Product laptop = dao.findById(1);
            System.out.println("\nFound: " + laptop);

            // Update price
            if (laptop != null) {
                laptop.setPrice(899.99);
                dao.update(laptop);
                System.out.println("Updated: " + dao.findById(1));
            }
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

