import java.sql.*;

public class StudentGradeSystem {
    private static final String URL = "jdbc:mysql://localhost:3306/school";
    private static final String USER = "root";
    private static final String PASS = "password";

    public static void main(String[] args) {
        try (Connection conn = DriverManager.getConnection(URL, USER, PASS)) {
            createTable(conn);
            insertStudents(conn);
            showAverageBySubject(conn);
            showTopStudent(conn);
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    static void createTable(Connection conn) throws SQLException {
        String sql = "CREATE TABLE IF NOT EXISTS students (" +
                     "id INT AUTO_INCREMENT PRIMARY KEY, " +
                     "name VARCHAR(100), " +
                     "subject VARCHAR(50), " +
                     "grade DOUBLE)";
        try (Statement stmt = conn.createStatement()) {
            stmt.executeUpdate(sql);
            System.out.println("Table created successfully.");
        }
    }

    static void insertStudents(Connection conn) throws SQLException {
        String sql = "INSERT INTO students (name, subject, grade) VALUES (?, ?, ?)";
        String[][] data = {
            {"Alice", "Math", "95"}, {"Alice", "Science", "88"},
            {"Bob", "Math", "78"}, {"Bob", "Science", "92"},
            {"Charlie", "Math", "88"}, {"Charlie", "Science", "85"}
        };
        try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
            for (String[] row : data) {
                pstmt.setString(1, row[0]);
                pstmt.setString(2, row[1]);
                pstmt.setDouble(3, Double.parseDouble(row[2]));
                pstmt.addBatch();
            }
            pstmt.executeBatch();
            System.out.println("3 students inserted.");
        }
    }

    static void showAverageBySubject(Connection conn) throws SQLException {
        String sql = "SELECT subject, AVG(grade) as avg_grade FROM students GROUP BY subject";
        System.out.println("\nAverage Grades by Subject:");
        try (Statement stmt = conn.createStatement();
             ResultSet rs = stmt.executeQuery(sql)) {
            while (rs.next()) {
                System.out.printf("%s: %.2f%n", rs.getString("subject"), rs.getDouble("avg_grade"));
            }
        }
    }

    static void showTopStudent(Connection conn) throws SQLException {
        String sql = "SELECT name, AVG(grade) as avg_grade FROM students " +
                     "GROUP BY name ORDER BY avg_grade DESC LIMIT 1";
        try (Statement stmt = conn.createStatement();
             ResultSet rs = stmt.executeQuery(sql)) {
            if (rs.next()) {
                System.out.printf("\nTop Student: %s (Average: %.2f)%n",
                    rs.getString("name"), rs.getDouble("avg_grade"));
            }
        }
    }
}

import java.sql.*;

public class InventoryManager {
    private static final String URL = "jdbc:mysql://localhost:3306/inventory";
    private static final String USER = "root";
    private static final String PASS = "password";

    public static void main(String[] args) {
        try (Connection conn = DriverManager.getConnection(URL, USER, PASS)) {
            setupTable(conn);
            addProducts(conn);
            bulkStockUpdate(conn);
            generateReport(conn);
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    static void setupTable(Connection conn) throws SQLException {
        String sql = "CREATE TABLE IF NOT EXISTS products (" +
                     "id INT AUTO_INCREMENT PRIMARY KEY, " +
                     "name VARCHAR(100) UNIQUE, " +
                     "price DOUBLE, " +
                     "quantity INT)";
        try (Statement stmt = conn.createStatement()) {
            stmt.executeUpdate(sql);
        }
    }

    static void addProducts(Connection conn) throws SQLException {
        String sql = "INSERT INTO products (name, price, quantity) VALUES (?, ?, ?)";
        try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
            Object[][] products = {{"Laptop", 999.00, 50}, {"Mouse", 29.00, 200}, {"Keyboard", 79.00, 150}};
            for (Object[] p : products) {
                pstmt.setString(1, (String) p[0]);
                pstmt.setDouble(2, (Double) p[1]);
                pstmt.setInt(3, (Integer) p[2]);
                pstmt.addBatch();
            }
            pstmt.executeBatch();
            System.out.println("Products added successfully.");
        }
    }

    static void bulkStockUpdate(Connection conn) throws SQLException {
        conn.setAutoCommit(false);
        try {
            String sql = "UPDATE products SET quantity = quantity - ? WHERE name = ? AND quantity >= ?";
            try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
                Object[][] updates = {{10, "Laptop"}, {50, "Mouse"}, {30, "Keyboard"}};
                for (Object[] u : updates) {
                    int qty = (Integer) u[0];
                    pstmt.setInt(1, qty);
                    pstmt.setString(2, (String) u[1]);
                    pstmt.setInt(3, qty);
                    pstmt.addBatch();
                }
                int[] results = pstmt.executeBatch();
                for (int result : results) {
                    if (result == 0) {
                        conn.rollback();
                        System.out.println("Insufficient stock. Transaction rolled back.");
                        return;
                    }
                }
            }
            conn.commit();
            System.out.println("\nBulk stock update completed.");
            System.out.println("Transaction committed.");
        } catch (SQLException e) {
            conn.rollback();
            throw e;
        } finally {
            conn.setAutoCommit(true);
        }
    }

    static void generateReport(Connection conn) throws SQLException {
        String sql = "SELECT name, price, quantity, (price * quantity) as value FROM products ORDER BY name";
        double totalValue = 0;
        System.out.println("\nInventory Report:");
        try (Statement stmt = conn.createStatement();
             ResultSet rs = stmt.executeQuery(sql)) {
            while (rs.next()) {
                double value = rs.getDouble("value");
                totalValue += value;
                System.out.printf("%-10s | $%.2f  | Stock: %-3d | Value: $%,.2f%n",
                    rs.getString("name"), rs.getDouble("price"),
                    rs.getInt("quantity"), value);
            }
        }
        System.out.printf("\nTotal Inventory Value: $%,.2f%n", totalValue);
    }
}
